using System;
using System.Linq;
using System.Text.Json;

namespace AvatarBuilder.Modules.Vision.MediaPipe.Reconstruction.Stereo;

public static class MediaPipeStereoRawEvidenceViewerPage
{
	private static readonly JsonSerializerOptions JsonOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

	public static string Build(MediaPipeStereoFaceState state)
	{
		ArgumentNullException.ThrowIfNull(state, "state");
		string value = JsonSerializer.Serialize(state.RawPointBins.Select((MediaPipeStereoRawPointBinState bin) => new object[5] { bin.MeanXInches, bin.MeanYInches, bin.MeanZInches, bin.ObservationCount, bin.AcceptedObservationCount }).ToArray(), JsonOptions).Replace("</", "<\\/", StringComparison.Ordinal);
		long value2 = state.RawPointBins.Sum((MediaPipeStereoRawPointBinState bin) => bin.AcceptedObservationCount);
		long value3 = state.RawPointBins.Sum((MediaPipeStereoRawPointBinState bin) => bin.ObservationCount);
		long value4 = ((state.RawPointBins.Count == 0) ? 0 : state.RawPointBins.Max((MediaPipeStereoRawPointBinState bin) => bin.ObservationCount));
		string value5 = ((state.UpdatedAtUtc == default(DateTime)) ? "" : state.UpdatedAtUtc.ToString("O"));
		string value6 = JsonSerializer.Serialize(string.IsNullOrWhiteSpace(state.SubjectDisplayName) ? state.SubjectId : state.SubjectDisplayName, JsonOptions);
		return $"<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>Raw Stereo Evidence</title>\n  <style>\n    :root{{color-scheme:dark;font-family:\"Segoe UI\",Arial,sans-serif;background:#061019;color:#e7f4ff}}\n    *{{box-sizing:border-box}}body{{margin:0;min-height:100vh;background:#061019}}\n    header{{height:54px;display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid #254052;background:#0a1721}}\n    button{{color:#e7f4ff;background:#10283a;border:1px solid #397397;padding:8px 12px;cursor:pointer}}button:hover{{border-color:#63c9ff}}.spacer{{flex:1}}\n    .layout{{height:calc(100vh - 54px);display:grid;grid-template-columns:minmax(0,1fr) 350px}}.stage{{position:relative;min-width:0;overflow:hidden}}\n    canvas{{width:100%;height:100%;display:block;background:#040b11;touch-action:none}}.hint{{position:absolute;left:14px;top:12px;padding:8px 10px;background:#07121dcc;border:1px solid #20394b;color:#b9d7ef;font-size:12px;pointer-events:none}}\n    aside{{overflow:auto;padding:16px;border-left:1px solid #254052;background:#08141d}}h1{{margin:0 0 4px;font-size:20px;letter-spacing:0}}h2{{margin:20px 0 8px;font-size:13px;color:#80e0a4;letter-spacing:0}}\n    p{{margin:5px 0;line-height:1.4}}.muted{{color:#9ebdd2;font-size:12px}}.metric{{display:grid;grid-template-columns:1fr auto;gap:10px;padding:7px 0;border-bottom:1px solid #193044;font-size:12px}}.metric strong{{color:#dff5ff;font-variant-numeric:tabular-nums}}\n    .legend{{display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:12px}}.legend div{{display:flex;align-items:center;gap:8px}}.swatch{{display:inline-block;width:18px;height:6px;border-radius:1px}}.note{{margin-top:16px;padding:10px;border:1px solid #2c627f;color:#bfe9ff;background:#081b27;font-size:12px;line-height:1.4}}\n    @media(max-width:800px){{.layout{{grid-template-columns:1fr;grid-template-rows:minmax(420px,65vh) auto;height:auto}}aside{{border-left:0;border-top:1px solid #254052}}}}\n  </style>\n</head>\n<body>\n  <header><button id=\"front\">Front</button><button id=\"side\">Side</button><button id=\"top\">Top</button><button id=\"reset\">Reset 3D View</button><span class=\"spacer\"></span><button id=\"updates\">Pause Updates</button><button id=\"refresh\">Refresh Now</button></header>\n  <main class=\"layout\">\n    <section class=\"stage\"><canvas id=\"view\"></canvas><div class=\"hint\">Every dot is a one-millimeter spatial bin. Drag to rotate; wheel to zoom.</div></section>\n    <aside><h1>Raw Stereo Evidence</h1><p><strong id=\"subject\"></strong></p><p class=\"muted\" id=\"updated\"></p><h2>Calculated Point Pileup</h2><div id=\"metrics\"></div>\n      <h2>Hits Per Spatial Bin</h2><div class=\"legend\"><div><span class=\"swatch\" style=\"background:#ff4057\"></span>1 hit</div><div><span class=\"swatch\" style=\"background:#ff8c42\"></span>2 hits</div><div><span class=\"swatch\" style=\"background:#ffd166\"></span>3 hits</div><div><span class=\"swatch\" style=\"background:#66e8b0\"></span>4 hits</div><div><span class=\"swatch\" style=\"background:#62d5ff\"></span>5 hits</div><div><span class=\"swatch\" style=\"background:#b889ff\"></span>6+ hits</div></div>\n      <div class=\"note\">This view intentionally includes accepted and rejected triangulated evidence. It is not the reconstructed face. Stable anatomy should emerge as repeated green, blue, and violet structures; isolated red points expose disagreement and calibration noise.</div>\n    </aside>\n  </main>\n  <script>\n    const bins={value},subject={value6},updated={JsonSerializer.Serialize(value5, JsonOptions)},acceptedVotes={value2},storedVotes={value3},rawVotes={state.RawTriangulatedObservationCount},unstoredVotes={state.RawUnstoredObservationCount},peakVotes={value4};\n    const canvas=document.getElementById('view'),gl=canvas.getContext('webgl',{{alpha:false,antialias:true,preserveDrawingBuffer:false}}),key='avatarBuilder.rawStereoEvidenceView';\n    let saved={{}};try{{saved=JSON.parse(localStorage.getItem(key)||'{{}}')}}catch{{}}let yaw=Number.isFinite(saved.yaw)?saved.yaw:-.35,pitch=Number.isFinite(saved.pitch)?saved.pitch:.08,zoom=Number.isFinite(saved.zoom)?saved.zoom:.78,dragging=false,lastX=0,lastY=0,updates=saved.updates!==false;\n    const metric=(l,v)=>`<div class=\"metric\"><span>${{l}}</span><strong>${{v}}</strong></div>`,save=()=>localStorage.setItem(key,JSON.stringify({{yaw,pitch,zoom,updates}}));\n    document.getElementById('subject').textContent=subject||'No profile';document.getElementById('updated').textContent=updated?`Updated ${{new Date(updated).toLocaleString()}}`:'Waiting for raw evidence';document.getElementById('metrics').innerHTML=metric('Triangulated observations',Number(rawVotes).toLocaleString())+metric('Stored observations',Number(storedVotes).toLocaleString())+metric('Occupied spatial bins',Number(bins.length).toLocaleString())+metric('Peak hits in one bin',Number(peakVotes).toLocaleString())+metric('Votes kept by face model',Number(acceptedVotes).toLocaleString())+metric('Votes rejected by face model',Number(Math.max(0,storedVotes-acceptedVotes)).toLocaleString())+metric('Outside diagnostic volume',Number(unstoredVotes).toLocaleString());\n    if(!gl){{document.querySelector('.hint').textContent='WebGL is unavailable in this browser.';throw new Error('WebGL unavailable')}}\n    const vertex=`attribute vec3 p;attribute vec4 c;attribute float s;uniform float yaw;uniform float pitch;uniform float zoom;uniform vec3 center;uniform float span;uniform vec2 viewportScale;varying vec4 color;void main(){{vec3 q=p-center;float cy=cos(yaw),sy=sin(yaw),cp=cos(pitch),sp=sin(pitch);vec3 y=vec3(cy*q.x+sy*q.z,q.y,-sy*q.x+cy*q.z);vec3 r=vec3(y.x,cp*y.y-sp*y.z,sp*y.y+cp*y.z);vec2 xy=(r.xy/max(span,.001))*2.0*zoom*viewportScale;gl_Position=vec4(xy,r.z/max(span,.001)*.15,1.0);gl_PointSize=s;color=c;}}`;\n    const fragment=`precision mediump float;varying vec4 color;void main(){{vec2 d=gl_PointCoord-vec2(.5);if(dot(d,d)>.25)discard;gl_FragColor=color;}}`;\n    function shader(type,source){{const s=gl.createShader(type);gl.shaderSource(s,source);gl.compileShader(s);if(!gl.getShaderParameter(s,gl.COMPILE_STATUS))throw new Error(gl.getShaderInfoLog(s));return s}}const program=gl.createProgram();gl.attachShader(program,shader(gl.VERTEX_SHADER,vertex));gl.attachShader(program,shader(gl.FRAGMENT_SHADER,fragment));gl.linkProgram(program);if(!gl.getProgramParameter(program,gl.LINK_STATUS))throw new Error(gl.getProgramInfoLog(program));gl.useProgram(program);\n    const count=bins.length,positions=new Float32Array(count*3),colors=new Float32Array(count*4),sizes=new Float32Array(count),palette=[[1,.251,.341],[1,.549,.259],[1,.82,.4],[.4,.91,.69],[.384,.835,1],[.722,.537,1]];let min=[Infinity,Infinity,Infinity],max=[-Infinity,-Infinity,-Infinity];\n    for(let i=0;i<count;i++){{const b=bins[i],hits=Math.max(1,Number(b[3])||1),pi=Math.min(5,hits-1),color=palette[pi];for(let a=0;a<3;a++){{const v=Number(b[a])||0;positions[i*3+a]=v;min[a]=Math.min(min[a],v);max[a]=Math.max(max[a],v)}}colors.set([color[0],color[1],color[2],.72],i*4);sizes[i]=Math.min(6,1.4+Math.log2(hits+1)*.72)}}\n    if(!count){{min=[-1,-1,-1];max=[1,1,1]}}const center=min.map((v,i)=>(v+max[i])/2),span=Math.max(.5,max[0]-min[0],max[1]-min[1],max[2]-min[2]);\n    function buffer(name,data,size){{const location=gl.getAttribLocation(program,name),b=gl.createBuffer();gl.bindBuffer(gl.ARRAY_BUFFER,b);gl.bufferData(gl.ARRAY_BUFFER,data,gl.STATIC_DRAW);gl.enableVertexAttribArray(location);gl.vertexAttribPointer(location,size,gl.FLOAT,false,0,0)}}buffer('p',positions,3);buffer('c',colors,4);buffer('s',sizes,1);\n    const u={{yaw:gl.getUniformLocation(program,'yaw'),pitch:gl.getUniformLocation(program,'pitch'),zoom:gl.getUniformLocation(program,'zoom'),center:gl.getUniformLocation(program,'center'),span:gl.getUniformLocation(program,'span'),viewportScale:gl.getUniformLocation(program,'viewportScale')}};gl.uniform3fv(u.center,new Float32Array(center));gl.uniform1f(u.span,span);gl.clearColor(.016,.043,.067,1);gl.enable(gl.BLEND);gl.blendFunc(gl.SRC_ALPHA,gl.ONE_MINUS_SRC_ALPHA);\n    function draw(){{gl.clear(gl.COLOR_BUFFER_BIT|gl.DEPTH_BUFFER_BIT);gl.uniform1f(u.yaw,yaw);gl.uniform1f(u.pitch,pitch);gl.uniform1f(u.zoom,zoom);const aspect=canvas.clientWidth/Math.max(1,canvas.clientHeight);gl.uniform2f(u.viewportScale,aspect>=1?1/aspect:1,aspect>=1?1:aspect);gl.drawArrays(gl.POINTS,0,count)}}\n    function resize(){{const dpr=Math.min(2,window.devicePixelRatio||1),r=canvas.getBoundingClientRect(),w=Math.max(1,Math.round(r.width*dpr)),h=Math.max(1,Math.round(r.height*dpr));if(canvas.width!==w||canvas.height!==h){{canvas.width=w;canvas.height=h;gl.viewport(0,0,w,h)}}draw()}}new ResizeObserver(resize).observe(canvas);\n    function setView(y,p,z=.78){{yaw=y;pitch=p;zoom=z;save();draw()}}document.getElementById('front').onclick=()=>setView(0,0);document.getElementById('side').onclick=()=>setView(-Math.PI/2,0);document.getElementById('top').onclick=()=>setView(0,-Math.PI/2);document.getElementById('reset').onclick=()=>setView(-.35,.08);document.getElementById('refresh').onclick=()=>location.reload();const updateButton=document.getElementById('updates');function updateLabel(){{updateButton.textContent=updates?'Pause Updates':'Resume Updates'}}updateLabel();updateButton.onclick=()=>{{updates=!updates;save();updateLabel()}};\n    canvas.addEventListener('pointerdown',e=>{{dragging=true;lastX=e.clientX;lastY=e.clientY;canvas.setPointerCapture(e.pointerId)}});canvas.addEventListener('pointermove',e=>{{if(!dragging)return;yaw+=(e.clientX-lastX)*.008;pitch=Math.max(-1.55,Math.min(1.55,pitch+(e.clientY-lastY)*.008));lastX=e.clientX;lastY=e.clientY;draw()}});canvas.addEventListener('pointerup',()=>{{dragging=false;save()}});canvas.addEventListener('wheel',e=>{{e.preventDefault();zoom=Math.max(.08,Math.min(6,zoom*Math.exp(-e.deltaY*.001)));save();draw()}},{{passive:false}});setInterval(()=>{{if(updates&&!dragging)location.reload()}},2500);\n  </script>\n</body>\n</html>";
	}
}
